import{_ as r,o as t,c as a,ai as i}from"./chunks/framework.Bke2s2V8.js";const p=JSON.parse('{"title":"Le futur","description":"","frontmatter":{},"headers":[],"relativePath":"module-4-le-temps/futur.md","filePath":"module-4-le-temps/futur.md","lastUpdated":1773298982000}'),s={name:"module-4-le-temps/futur.md"};function d(n,e,l,o,u,m){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="le-futur" tabindex="-1">Le futur <a class="header-anchor" href="#le-futur" aria-label="Permalink to “Le futur”">​</a></h1><p><strong>Prérequis :</strong> <a href="./prateritum.html">Le Präteritum</a></p><p><strong>Objectif :</strong> exprimer le futur en allemand - avec ou sans werden.</p><p>L&#39;allemand a deux façons d&#39;exprimer le futur. La plus simple est aussi la plus utilisée.</p><h2 id="le-present-a-valeur-de-futur" tabindex="-1">Le présent à valeur de futur <a class="header-anchor" href="#le-present-a-valeur-de-futur" aria-label="Permalink to “Le présent à valeur de futur”">​</a></h2><p>En allemand, comme en français, le présent suffit souvent à exprimer le futur quand le contexte temporel est clair. C&#39;est la forme la plus naturelle à l&#39;oral.</p><ul><li><em>Ich fahre morgen nach Berlin.</em> - Je vais a Berlin demain.</li><li><em>Er kommt um 8 Uhr.</em> - Il arrive a 8h.</li><li><em>Wir essen heute Abend im Restaurant.</em> - Ce soir on mange au restaurant.</li></ul><div class="tip custom-block"><p class="custom-block-title">Le présent + indicateur de temps = futur</p><p>Un mot comme <em>morgen</em> (demain), <em>heute Abend</em> (ce soir), <em>nachste Woche</em> (la semaine prochaine) suffit a signaler que la phrase parlé du futur. Dans ce cas, le présent est preferable a werden dans la conversation.</p></div><h2 id="werden-infinitif-le-futur-formel" tabindex="-1">werden + infinitif : le futur formel <a class="header-anchor" href="#werden-infinitif-le-futur-formel" aria-label="Permalink to “werden + infinitif : le futur formel”">​</a></h2><p><em>Werden</em> conjugué + infinitif en fin de phrase. Cette structure s&#39;utilisé pour des prédictions, des promesses ou pour insister sur le caractère futur de l&#39;action.</p><div class="mt-4 p-4 rounded-xl border border-gray-200"><div class="grid grid-cols-4 gap-2 text-center"><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet</div><div class="font-bold text-blue-800">Ich</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">werden (pos. 2)</div><div class="font-bold text-green-800">werde</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Complement</div><div class="font-bold text-gray-700">es</div></div><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Infinitif (fin)</div><div class="font-bold text-orange-800">schaffen.</div></div></div><div class="text-sm text-gray-500 text-center mt-3">Je vais y arriver.</div></div><h3 id="conjugaison-de-werden-rappel" tabindex="-1">Conjugaison de werden (rappel) <a class="header-anchor" href="#conjugaison-de-werden-rappel" aria-label="Permalink to “Conjugaison de werden (rappel)”">​</a></h3><table tabindex="0"><thead><tr><th>Pronom</th><th>werden</th></tr></thead><tbody><tr><td>ich</td><td><strong>werde</strong></td></tr><tr><td>du</td><td><strong>wirst</strong></td></tr><tr><td>er/sie/es</td><td><strong>wird</strong></td></tr><tr><td>wir</td><td><strong>werden</strong></td></tr><tr><td>ihr</td><td><strong>werdet</strong></td></tr><tr><td>sie/Sie</td><td><strong>werden</strong></td></tr></tbody></table><h3 id="exemples-avec-werden" tabindex="-1">Exemples avec werden <a class="header-anchor" href="#exemples-avec-werden" aria-label="Permalink to “Exemples avec werden”">​</a></h3><ul><li><em>Es wird morgen regnen.</em> - Il va pleuvoir demain. (prediction meteo)</li><li><em>Du wirst das verstehen.</em> - Tu vas comprendre ca.</li><li><em>Wir werden sehen.</em> - On verra bien.</li><li><em>Das wird gut sein.</em> - Ca va être bien.</li></ul><h2 id="comparaison-des-deux-formes" tabindex="-1">Comparaison des deux formes <a class="header-anchor" href="#comparaison-des-deux-formes" aria-label="Permalink to “Comparaison des deux formes”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-gray-200"><div class="flex justify-between items-start gap-4"><div><div class="font-semibold text-gray-800">Présent a valeur de futur</div><div class="text-sm text-gray-600 italic mt-1">Ich fahre morgen nach Paris.</div></div><div class="text-sm text-gray-500 text-right shrink-0">Oral, naturel, plan concret</div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="flex justify-between items-start gap-4"><div><div class="font-semibold text-gray-800">werden + infinitif</div><div class="text-sm text-gray-600 italic mt-1">Ich werde nach Paris fahren.</div></div><div class="text-sm text-gray-500 text-right shrink-0">Prediction, promesse, emphase</div></div></div></div><div class="warning custom-block"><p class="custom-block-title">werden peut aussi exprimer la probabilite au présent</p><p><em>Er wird krank sein.</em> peut signifier &quot;il doit probablement être malade&quot; (supposition sur le présent), pas seulement &quot;il sera malade&quot; (futur). Le contexte tranche. Cette nuance est avancee - a noter pour plus tard.</p></div>',18)])])}const f=r(s,[["render",d]]);export{p as __pageData,f as default};
